var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"더, 더는 못 버티겠어...... 잠이 와......","JPN":"こ、これ以上は無理……眠い……","ENG":"I-I can't fight it any longer... I'm getting sleepy...","TWN":"我，我撐不下去了……太睏了……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이 멍청아! 지금 잠들면 끝장이야!","JPN":"このバカ！　今眠ったら終わりだ！","ENG":"You idiot! You'll die if you fall asleep!","TWN":"蠢貨！現在睡著就死定了！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"에블린! 이 녀석 좀 깨워 봐!","JPN":"エヴリン！　こいつを起こせ！","ENG":"Evelyn! Wake up the little fool!","TWN":"伊芙琳！妳快叫醒她！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"에블린......?","JPN":"エヴリン……？","ENG":"Evelyn?","TWN":"伊芙琳……！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"젠장, 너까지 쓰러지면 어쩌라는 거야?","JPN":"クソ、汝まで倒れてしまったらどうするんだ！","ENG":"Oh, please! Don't tell me you passed out!","TWN":"可惡，怎麼可以連妳都倒下！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"눈 떠! 눈 뜨라고!!","JPN":"目を覚ませ！　目を覚ませってば！！","ENG":"Open your eyes! Wake up!","TWN":"睜開眼睛！睜開眼睛啊！！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"당신들의 열기가 사그라드는 게 느껴지네요.","JPN":"あなたたちの熱が消えていくのを感じますわ。","ENG":"I can sense the warmth drain from your bodies.","TWN":"我能感受到妳們的體溫漸漸消退。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"안심하세요. 고통은 없을 테니.","JPN":"ご安心を。苦しみはないと思いますので。","ENG":"Don't worry. This will be painless.","TWN":"放心吧，不會有任何痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"저는 어머니와 다르거든요. 제물에게 불필요한 고통은 주지 않습니다.","JPN":"私は母とは違いますから。供え物に不要な苦しみは与えませんわ。","ENG":"Unlike my mother, I do not delight in inflicting unnecessary pain on the sacrifices.","TWN":"我和母親不同，我不會給祭品不必要的痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"그저 차갑게...... 잠들어 버리세요.","JPN":"ただ冷たく……眠りなさい。","ENG":"Just let the cold lull you to sleep.","TWN":"就這麼冷冷地……沉睡下去吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_CODEX_NULL_QM","text":{"KOREA":"미안하지만 냉기 따윈 사절이야.","JPN":"悪いが冷気なんてごめんだ。","ENG":"Sorry, but I hate the cold.","TWN":"抱歉，我可不喜歡寒冷。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_CODEX_NULL_QM","text":{"KOREA":"난 추운 것보다는 뜨거운 게 좋거든?","JPN":"俺は冷たいのより熱い方が好きだからな。","ENG":"I prefer things hot!","TWN":"比起寒冷，我還是比較喜歡溫暖！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"내 얼음 기둥을 녹이다니......! 대체 어디서 이런 불길이......?!","JPN":"私の氷柱が溶けるなんて……！　いったいどこからこんな炎が……？","ENG":"My ice pillars have melted! Were did such flames come from?","TWN":"居然融掉了我的冰柱……！到底是哪裡來的火……？！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"몸이...... 따뜻해졌어. 어떻게 된 거지?","JPN":"体が……暖かくなった。どういうことだ？","ENG":"I feel... warm. What happened?","TWN":"身體……熱起來了。到底是怎麼回事？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으음......","JPN":"うーん……","ENG":"Hngh...","TWN":"唔……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"에블린? 정신이 들어?!","JPN":"エヴリン？　気がついたか？","ENG":"Evelyn? Are you okay?","TWN":"伊芙琳？妳醒了？！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"간신히 죽지는 않은 것 같아......","JPN":"辛うじて生きてるみたい……","ENG":"I'm alive... barely...","TWN":"我還沒死……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그런데 저 불새, 어디서 본 것 같지 않아?","JPN":"ところであの火の鳥、どこかで見たことあるんじゃない？","ENG":"Is it me, or does that firebird look familiar?","TWN":"那個火鳥，有沒有覺得在哪裡見過？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"불새......? 레일리?!","JPN":"火の鳥……？　レイリー？","ENG":"Firebird? Rayleigh?!","TWN":"火鳥……？瑞利？！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"설마, 그 바보가 솔라 코덱스를 펼치는 데 성공했나?","JPN":"まさかあのバカがソーラーコーデックスを開いたのか？","ENG":"No way... Did the rookie manage to open the Solar Codex?","TWN":"難道，那個傻瓜成功施展了太陽法典？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"태양의 대마녀, 유나 스프링필드! 여기 도착!","JPN":"太陽の大魔女、ユナ・スプリングフィールド！　ここに参上！","ENG":"The Great Witch of the Sun, Yuna Springfield has arrived!","TWN":"太陽的大魔女，尤娜！登場！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_04"},{"id":"L34_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"대마녀 같은 소리 하고 있네. 너 같은 애송이가 대마녀는 무슨.","JPN":"大魔女なんてふざけるな。お前みたいな雑魚の何が大魔女だ。","ENG":"Great witch, my butt. You're just a fledgling.","TWN":"什麼大魔女，妳就是個小鬼。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L35_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"그, 그치만 대마녀 급만 솔라 코덱스를 펼칠 수 있다면서요?","JPN":"で、でも大魔女のみがソーラーコーデックスを開くことができると言ってたよね？","ENG":"B-but didn't you say only a great witch could open the Solar Codex?","TWN":"可、可你不是說只有大魔女級別的才可以施展太陽法典嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"시끄러워! 대마녀가 그렇게 만만한 직업인 줄 알아?","JPN":"うるさい！　大魔女を甘く見るんじゃない。","ENG":"Shut up! You think it's that easy to become a great witch?","TWN":"閉嘴！妳以為大魔女有那麼容易當上嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L38_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"정 그렇게 부르고 싶다면 견습 대마녀 정도는 허락하지!","JPN":"そう自称したいなら見習い大魔女くらいは許す！","ENG":"If you really want to use that title, I guess you could go with great witch-in-training.","TWN":"如果妳非得稱自己為大魔女，我倒是可以允許妳稱自己為見習大魔女！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"히잉...... 여기서도 또 견습이야......","JPN":"はうぅ……まだ見習いかあ……","ENG":"Aw... Not in training again...","TWN":"嗚嗚……又是見習……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"......누구신지 몰라도 제법 괜찮은 열기를 두르고 있군요.","JPN":"……どなたか知りませんが、なかなかいい熱気を纏っているのですね。","ENG":"Whoever you are, you possess quite an admirable amount of heat.","TWN":"……我雖然不知道你是誰，但你的熱氣倒是很不錯。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"얼려 버리는 재미가 있겠어요.","JPN":"凍らせる面白さがありますわ。","ENG":"I'm going to have extra fun freezing you.","TWN":"讓我提起了興趣。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"잡담 끝났다. 긴장해라, 애송아.","JPN":"おしゃべりタイムは終わりだ。気を引き締めろ、雑魚。","ENG":"Enough with the small talk. Time to focus, fledgling.","TWN":"閒話到此為止，小鬼，妳可要緊張了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L46_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"저 얼음덩어리 여자는 네 할머니가 전성기일 때도 몇 번 만나지 못한 강적이니까.","JPN":"あの氷の女はお前の婆さんが全盛期の時に戦った相手と比べても指折りの強敵だぞ。","ENG":"I've rarely seen anyone as strong as that icy lady, even when your grandmother was in her prime.","TWN":"妳奶奶在巔峰的時候也沒遇到過幾次那個冰塊女，她可是個強勁的對手。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"알겠어요!","JPN":"わかった！","ENG":"Got it!","TWN":"知道了！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"그렇다고 너무 겁먹을 필요는 없어.","JPN":"でもそこまでビビる必要はない。","ENG":"But there's no need to get too nervous.","TWN":"但也沒必要太害怕。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"태양의 불길이 겨우 얼음 따위에 꺼질 리 있겠냐?","JPN":"太陽の炎が氷なんかに負けるわけがないからな。","ENG":"No ice could freeze the sun, after all.","TWN":"太陽的火焰才不會被區區冰塊澆熄！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"자, 가자! 해방된 솔라 코덱스의 힘을 보여 줘라!","JPN":"さあ、行くぞ！　解放したソーラーコーデックスの力を見せてやれ！","ENG":"Let's go! Unleash the full power of the Solar Codex!","TWN":"走吧！讓她瞧瞧太陽法典的力量！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};